3	export type TransportState = "stopped" | "playing" | "paused";
4	
5	export type AudioEngineStatus =
6	  | "uninitialized"
7	  | "suspended"
8	  | "running"
9	  | "error";
10	
11	export type DawStore = {
12	  // Transport
13	  transportState: TransportState;
14	  bpm: number;
15	  cursorSeconds: number;
16	  loopEnabled: boolean;
17	  loopStart: number;
18	  loopEnd: number;
19	
20	  // Audio engine
21	  engineStatus: AudioEngineStatus;
22	
23	  // Transport actions
24	  play: () => void;
25	  pause: () => void;
26	  stop: () => void;
27	  setBpm: (bpm: number) => void;
28	  setCursor: (seconds: number) => void;
29	  setLoop: (enabled: boolean, start?: number, end?: number) => void;
30	
31	  // Engine actions
32	  setEngineStatus: (status: AudioEngineStatus) => void;
33	};
34	
35	export const useDawStore = create<DawStore>()((set) => ({
36	  // Transport defaults
37	  transportState: "stopped",
38	  bpm: 120,
39	  cursorSeconds: 0,
40	  loopEnabled: false,
41	  loopStart: 0,
42	  loopEnd: 0,
43	
44	  // Engine defaults
45	  engineStatus: "uninitialized",
46	
47	  // Transport actions
48	  play: () => {
49	    set({ transportState: "playing" });
50	  },
51	  pause: () => {
52	    set({ transportState: "paused" });
53	  },
54	  stop: () => {
55	    set({ transportState: "stopped", cursorSeconds: 0 });
56	  },
57	  setBpm: (bpm: number) => {
58	    const clamped = Math.min(999, Math.max(20, bpm));
59	    if (!Number.isFinite(clamped)) return;
60	    set({ bpm: clamped });
61	  },
62	  setCursor: (seconds: number) => {
63	    set({ cursorSeconds: seconds });
64	  },
65	  setLoop: (enabled: boolean, start?: number, end?: number) => {
66	    set((state) => ({
67	      loopEnabled: enabled,
68	      loopStart: start ?? state.loopStart,
69	      loopEnd: end ?? state.loopEnd,
70	    }));
71	  },
72	
73	  // Engine actions
74	  setEngineStatus: (status: AudioEngineStatus) => {
75	    set({ engineStatus: status });
76	  },
77	}));
