1	import type { AudioSourceHandle, WaveformPeaks } from "./types";
2	
3	/** Storage interface for media pool persistence. */
4	export type MediaPoolStorage = {
5	  putBlob(id: string, blob: Blob): Promise<void>;
6	  getBlob(id: string): Promise<Blob | undefined>;
7	  deleteBlob(id: string): Promise<void>;
8	  putMeta(id: string, meta: AudioSourceHandle): Promise<void>;
9	  getMeta(id: string): Promise<AudioSourceHandle | undefined>;
10	  getAllMeta(): Promise<AudioSourceHandle[]>;
11	  deleteMeta(id: string): Promise<void>;
12	  putPeaks(key: string, peaks: WaveformPeaks): Promise<void>;
13	  getPeaks(key: string): Promise<WaveformPeaks | undefined>;
14	  deletePeaksBySource(sourceId: string): Promise<void>;
15	};
16	
17	/** In-memory implementation for testing. */
18	export function createInMemoryStorage(): MediaPoolStorage {
19	  const blobs = new Map<string, Blob>();
20	  const meta = new Map<string, AudioSourceHandle>();
21	  const peaks = new Map<string, WaveformPeaks>();
22	
23	  return {
24	    putBlob(id, blob): Promise<void> {
25	      blobs.set(id, blob);
26	      return Promise.resolve();
27	    },
28	    getBlob(id): Promise<Blob | undefined> {
29	      return Promise.resolve(blobs.get(id));
30	    },
31	    deleteBlob(id): Promise<void> {
32	      blobs.delete(id);
33	      return Promise.resolve();
34	    },
35	    putMeta(id, handle): Promise<void> {
36	      meta.set(id, handle);
37	      return Promise.resolve();
38	    },
39	    getMeta(id): Promise<AudioSourceHandle | undefined> {
40	      return Promise.resolve(meta.get(id));
41	    },
42	    getAllMeta(): Promise<AudioSourceHandle[]> {
43	      return Promise.resolve([...meta.values()]);
44	    },
45	    deleteMeta(id): Promise<void> {
46	      meta.delete(id);
47	      return Promise.resolve();
48	    },
49	    putPeaks(key, data): Promise<void> {
50	      peaks.set(key, data);
51	      return Promise.resolve();
52	    },
53	    getPeaks(key): Promise<WaveformPeaks | undefined> {
54	      return Promise.resolve(peaks.get(key));
55	    },
56	    deletePeaksBySource(sourceId): Promise<void> {
57	      for (const key of [...peaks.keys()]) {
58	        if (key.startsWith(`${sourceId}:`)) {
59	          peaks.delete(key);
60	        }
61	      }
62	      return Promise.resolve();
63	    },
64	  };
65	}
