67	const DB_NAME = "brutalwav-media";
68	const DB_VERSION = 1;
69	const STORE_BLOBS = "blobs";
70	const STORE_META = "meta";
71	const STORE_PEAKS = "peaks";
72	
73	function openDb(): Promise<IDBDatabase> {
74	  return new Promise((resolve, reject) => {
75	    const req = indexedDB.open(DB_NAME, DB_VERSION);
76	    req.onupgradeneeded = (): void => {
77	      const db = req.result;
78	      if (!db.objectStoreNames.contains(STORE_BLOBS)) {
79	        db.createObjectStore(STORE_BLOBS);
80	      }
81	      if (!db.objectStoreNames.contains(STORE_META)) {
82	        db.createObjectStore(STORE_META);
83	      }
84	      if (!db.objectStoreNames.contains(STORE_PEAKS)) {
85	        db.createObjectStore(STORE_PEAKS);
86	      }
87	    };
88	    req.onsuccess = (): void => {
89	      resolve(req.result);
90	    };
91	    req.onerror = (): void => {
92	      reject(req.error ?? new Error("IndexedDB open failed"));
93	    };
94	  });
95	}
96	
97	function idbPut(
98	  db: IDBDatabase,
99	  store: string,
100	  key: string,
101	  value: unknown,
102	): Promise<void> {
103	  return new Promise((resolve, reject) => {
104	    const tx = db.transaction(store, "readwrite");
105	    tx.objectStore(store).put(value, key);
106	    tx.oncomplete = (): void => {
107	      resolve();
108	    };
109	    tx.onerror = (): void => {
110	      reject(tx.error ?? new Error("IndexedDB put failed"));
111	    };
112	  });
113	}
114	
115	function idbGet<T>(
116	  db: IDBDatabase,
117	  store: string,
118	  key: string,
119	): Promise<T | undefined> {
120	  return new Promise((resolve, reject) => {
121	    const tx = db.transaction(store, "readonly");
122	    const req = tx.objectStore(store).get(key);
123	    req.onsuccess = (): void => {
124	      resolve(req.result as T | undefined);
125	    };
126	    req.onerror = (): void => {
127	      reject(req.error ?? new Error("IndexedDB get failed"));
128	    };
129	  });
130	}
131	
132	function idbDelete(db: IDBDatabase, store: string, key: string): Promise<void> {
133	  return new Promise((resolve, reject) => {
134	    const tx = db.transaction(store, "readwrite");
135	    tx.objectStore(store).delete(key);
136	    tx.oncomplete = (): void => {
137	      resolve();
138	    };
139	    tx.onerror = (): void => {
140	      reject(tx.error ?? new Error("IndexedDB delete failed"));
141	    };
142	  });
143	}
144	
145	function idbGetAll<T>(db: IDBDatabase, store: string): Promise<T[]> {
146	  return new Promise((resolve, reject) => {
147	    const tx = db.transaction(store, "readonly");
148	    const req = tx.objectStore(store).getAll();
149	    req.onsuccess = (): void => {
150	      resolve(req.result as T[]);
151	    };
152	    req.onerror = (): void => {
153	      reject(req.error ?? new Error("IndexedDB getAll failed"));
154	    };
155	  });
156	}
157	
158	function idbGetAllKeys(db: IDBDatabase, store: string): Promise<string[]> {
159	  return new Promise((resolve, reject) => {
160	    const tx = db.transaction(store, "readonly");
161	    const req = tx.objectStore(store).getAllKeys();
162	    req.onsuccess = (): void => {
163	      resolve(req.result as string[]);
164	    };
165	    req.onerror = (): void => {
166	      reject(req.error ?? new Error("IndexedDB getAllKeys failed"));
167	    };
168	  });
169	}
170	
171	/** IndexedDB-backed storage for production use. */
172	export function createIndexedDBStorage(): MediaPoolStorage {
173	  let dbPromise: Promise<IDBDatabase> | null = null;
174	
175	  function getDb(): Promise<IDBDatabase> {
176	    if (dbPromise === null) {
177	      dbPromise = openDb();
178	    }
179	    return dbPromise;
180	  }
181	
182	  return {
183	    async putBlob(id, blob): Promise<void> {
184	      const db = await getDb();
185	      await idbPut(db, STORE_BLOBS, id, blob);
186	    },
187	    async getBlob(id): Promise<Blob | undefined> {
188	      const db = await getDb();
189	      return idbGet<Blob>(db, STORE_BLOBS, id);
190	    },
191	    async deleteBlob(id): Promise<void> {
192	      const db = await getDb();
193	      await idbDelete(db, STORE_BLOBS, id);
194	    },
195	    async putMeta(id, handle): Promise<void> {
196	      const db = await getDb();
197	      await idbPut(db, STORE_META, id, handle);
198	    },
199	    async getMeta(id): Promise<AudioSourceHandle | undefined> {
200	      const db = await getDb();
201	      return idbGet<AudioSourceHandle>(db, STORE_META, id);
202	    },
203	    async getAllMeta(): Promise<AudioSourceHandle[]> {
204	      const db = await getDb();
205	      return idbGetAll<AudioSourceHandle>(db, STORE_META);
206	    },
207	    async deleteMeta(id): Promise<void> {
208	      const db = await getDb();
209	      await idbDelete(db, STORE_META, id);
210	    },
211	    async putPeaks(key, data): Promise<void> {
212	      const db = await getDb();
213	      await idbPut(db, STORE_PEAKS, key, data);
214	    },
215	    async getPeaks(key): Promise<WaveformPeaks | undefined> {
216	      const db = await getDb();
217	      return idbGet<WaveformPeaks>(db, STORE_PEAKS, key);
218	    },
219	    async deletePeaksBySource(sourceId): Promise<void> {
220	      const db = await getDb();
221	      const keys = await idbGetAllKeys(db, STORE_PEAKS);
222	      const toDelete = keys.filter((k) => k.startsWith(`${sourceId}:`));
223	      if (toDelete.length === 0) return;
224	
225	      // Batch all deletes in a single transaction
226	      await new Promise<void>((resolve, reject) => {
227	        const tx = db.transaction(STORE_PEAKS, "readwrite");
228	        const store = tx.objectStore(STORE_PEAKS);
229	        for (const key of toDelete) {
230	          store.delete(key);
231	        }
232	        tx.oncomplete = (): void => {
233	          resolve();
234	        };
235	        tx.onerror = (): void => {
236	          reject(tx.error ?? new Error("IndexedDB batch delete failed"));
237	        };
238	      });
239	    },
240	  };
241	}
