1	import type { MediaPoolStorage } from "./idb-storage";
2	import { decodeAudioFile } from "./decode-pipeline";
3	import { computeWaveformPeaks } from "./waveform-peaks";
4	import type {
5	  AudioSourceHandle,
6	  DecodeResult,
7	  MediaPool,
8	  WaveformPeaks,
9	} from "./types";
10	
11	const DEFAULT_SAMPLES_PER_PEAK = 256;
12	
13	export function createMediaPool(
14	  ctx: BaseAudioContext,
15	  storage: MediaPoolStorage,
16	): MediaPool {
17	  const sources = new Map<string, AudioSourceHandle>();
18	  const bufferCache = new Map<string, AudioBuffer>();
19	
20	  const pool: MediaPool = {
21	    async init(): Promise<void> {
22	      const metas = await storage.getAllMeta();
23	      for (const meta of metas) {
24	        sources.set(meta.id, meta);
25	      }
26	    },
27	
28	    async importFile(file: File): Promise<DecodeResult> {
29	      const result = await decodeAudioFile(file, ctx);
30	      if (!result.ok) return result;
31	
32	      const { handle, buffer } = result;
33	
34	      // Store blob and metadata (File extends Blob, no extra copy needed)
35	      try {
36	        await storage.putBlob(handle.id, file);
37	      } catch (e: unknown) {
38	        if (e instanceof DOMException && e.name === "QuotaExceededError") {
39	          return {
40	            ok: false,
41	            error: { kind: "storage-full", fileName: file.name },
42	          };
43	        }
44	        throw e;
45	      }
46	      try {
47	        await storage.putMeta(handle.id, handle);
48	
49	        // Compute and cache peaks at default resolution
50	        const peaks = computeWaveformPeaks(
51	          buffer,
52	          DEFAULT_SAMPLES_PER_PEAK,
53	          handle.id,
54	        );
55	        await storage.putPeaks(
56	          `${handle.id}:${String(DEFAULT_SAMPLES_PER_PEAK)}`,
57	          peaks,
58	        );
59	      } catch (e: unknown) {
60	        // Rollback blob to prevent orphaned storage
61	        await storage.deleteBlob(handle.id).catch(() => {});
62	        throw e;
63	      }
64	
65	      sources.set(handle.id, handle);
66	      bufferCache.set(handle.id, buffer);
67	      return result;
68	    },
69	
70	    getSource(id: string): AudioSourceHandle | undefined {
71	      return sources.get(id);
72	    },
73	
74	    async getAudioBuffer(id: string): Promise<AudioBuffer | undefined> {
75	      const cached = bufferCache.get(id);
76	      if (cached !== undefined) return cached;
77	
78	      const blob = await storage.getBlob(id);
79	      if (blob === undefined) return undefined;
80	
81	      const arrayBuffer = await blob.arrayBuffer();
82	      const decoded = await ctx.decodeAudioData(arrayBuffer);
83	      bufferCache.set(id, decoded);
84	      return decoded;
85	    },
86	
87	    async getPeaks(
88	      id: string,
89	      samplesPerPeak: number,
90	    ): Promise<WaveformPeaks | undefined> {
91	      const key = `${id}:${String(samplesPerPeak)}`;
92	      return storage.getPeaks(key);
93	    },
94	
95	    listSources(): readonly AudioSourceHandle[] {
96	      return [...sources.values()];
97	    },
98	
99	    async removeSource(id: string): Promise<void> {
100	      await storage.deleteBlob(id);
101	      await storage.deleteMeta(id);
102	      await storage.deletePeaksBySource(id);
103	      sources.delete(id);
104	      bufferCache.delete(id);
105	    },
106	
107	    get count(): number {
108	      return sources.size;
109	    },
110	  };
111	
112	  return pool;
113	}
