15	export function App(): React.JSX.Element {
16	  const crossOriginOk = isCrossOriginIsolated();
17	  const [engine, setEngine] = useState<AudioEngineContext | null>(null);
18	  const [pool, setPool] = useState<MediaPool | null>(null);
19	  const engineRef = useRef<AudioEngineContext | null>(null);
20	  const setEngineStatus = useDawStore((s) => s.setEngineStatus);
21	
22	  useEffect(() => {
23	    if (engine === null) return;
24	    const storage = createIndexedDBStorage();
25	    const p = createMediaPool(engine.ctx, storage);
26	    let cancelled = false;
27	    p.init().then(
28	      () => {
29	        if (!cancelled) setPool(p);
30	      },
31	      () => {
32	        // IDB init failed -- pool works but starts empty
33	        if (!cancelled) setPool(p);
34	      },
35	    );
36	    return () => {
37	      cancelled = true;
38	      setPool(null);
39	    };
40	  }, [engine]);
41	
42	  const handleStart = useCallback((): void => {
43	    if (engineRef.current) return;
44	
45	    let newEngine: AudioEngineContext;
46	    try {
47	      newEngine = createAudioEngine();
48	    } catch {
49	      setEngineStatus("error");
50	      return;
51	    }
52	
53	    engineRef.current = newEngine;
54	    newEngine.resume().then(
55	      () => {
56	        if (engineRef.current !== newEngine) return;
57	        setEngineStatus("running");
58	        setEngine(newEngine);
59	      },
60	      () => {
61	        void newEngine.close();
62	        if (engineRef.current === newEngine) {
63	          engineRef.current = null;
64	        }
65	        setEngineStatus("error");
66	      },
67	    );
68	  }, [setEngineStatus]);
69	
70	  useEffect(() => {
71	    return () => {
72	      void engineRef.current?.close();
73	      engineRef.current = null;
74	    };
75	  }, []);
76	
77	  if (!crossOriginOk) {
78	    return <CrossOriginError />;
79	  }
80	
81	  if (engine === null || pool === null) {
82	    return <ClickToStart onStart={handleStart} />;
83	  }
84	
85	  return (
86	    <AudioEngineProvider engine={engine}>
87	      <MediaPoolProvider pool={pool}>
88	        <DawShell />
89	      </MediaPoolProvider>
90	    </AudioEngineProvider>
91	  );
