3	export type TransportState = "stopped" | "playing" | "paused";
4	
5	export type AudioEngineStatus =
6	  | "uninitialized"
7	  | "suspended"
8	  | "running"
9	  | "error";
10	
11	export type DawStore = {
12	  // Transport
13	  transportState: TransportState;
14	  bpm: number;
15	  cursorSeconds: number;
16	  loopEnabled: boolean;
17	  loopStart: number;
18	  loopEnd: number;
19	
20	  // Audio engine
21	  engineStatus: AudioEngineStatus;
22	
23	  // Transport actions
24	  play: () => void;
25	  pause: () => void;
26	  stop: () => void;
27	  setBpm: (bpm: number) => void;
28	  setCursor: (seconds: number) => void;
29	  setLoop: (enabled: boolean, start?: number, end?: number) => void;
30	
31	  // Engine actions
32	  setEngineStatus: (status: AudioEngineStatus) => void;
33	};
