11	export function Modal({
12	  open,
13	  onClose,
14	  title,
15	  children,
16	}: ModalProps): React.JSX.Element {
17	  const dialogRef = useRef<HTMLDialogElement>(null);
18	
19	  useEffect(() => {
20	    const dialog = dialogRef.current;
21	    if (dialog === null) return;
22	
23	    if (open) {
24	      if (!dialog.open) {
25	        dialog.showModal();
26	      }
27	      dialog.setAttribute("open", "");
28	    } else {
29	      if (dialog.open) {
30	        dialog.close();
31	      }
32	      dialog.removeAttribute("open");
33	    }
34	  }, [open]);
35	
36	  useEffect(() => {
37	    const dialog = dialogRef.current;
38	    if (dialog === null) return;
39	
40	    const handleClose = (): void => {
41	      onClose();
42	    };
43	
44	    dialog.addEventListener("close", handleClose);
45	    return () => {
46	      dialog.removeEventListener("close", handleClose);
47	    };
48	  }, [onClose]);
49	
50	  return (
51	    <dialog
52	      ref={dialogRef}
53	      className={styles.dialog}
54	      data-testid="modal-dialog"
55	    >
56	      <div className={styles.titleBar}>{title}</div>
57	      <div className={styles.body}>{children}</div>
58	    </dialog>
59	  );
