69	function formatError(error: MediaPoolError): string {
70	  switch (error.kind) {
71	    case "decode-failed":
72	      return `Failed to decode "${error.fileName}". Try WAV, MP3, OGG, or FLAC format.`;
73	    case "unsupported-format":
74	      return `Unsupported format: "${error.fileName}". Try WAV, MP3, OGG, or FLAC.`;
75	    case "file-too-large":
76	      return `File "${error.fileName}" is too large (max 500MB).`;
77	    case "storage-full":
78	      return `Storage full. Cannot import "${error.fileName}".`;
79	  }
80	}
81	
82	export function MediaPoolPanel({
83	  pool,
84	}: MediaPoolPanelProps): React.JSX.Element {
85	  const fileInputRef = useRef<HTMLInputElement>(null);
86	  const [version, setVersion] = useState(0);
87	  const sources = useMemo(() => pool.listSources(), [pool, version]); // eslint-disable-line react-hooks/exhaustive-deps
88	  const [peaksMap, setPeaksMap] = useState(new Map<string, WaveformPeaks>());
89	  const [errors, setErrors] = useState<MediaPoolError[]>([]);
90	  const importingRef = useRef(false);
91	
92	  useEffect(() => {
93	    // Load cached peaks for persisted sources
94	    void Promise.all(
95	      sources.map(async (source) => {
96	        if (peaksMap.has(source.id)) return;
97	        const peaks = await pool.getPeaks(source.id, 256);
98	        if (peaks !== undefined) {
99	          setPeaksMap((prev) => {
100	            const next = new Map(prev);
101	            next.set(source.id, peaks);
102	            return next;
103	          });
104	        }
105	      }),
106	    );
107	  }, [sources, pool]); // eslint-disable-line react-hooks/exhaustive-deps
108	
109	  const handleImport = useCallback(
110	    async (files: File[]) => {
111	      if (importingRef.current) return;
112	      importingRef.current = true;
113	      setErrors([]);
114	      try {
115	        const importErrors: MediaPoolError[] = [];
116	        for (const file of files) {
117	          const result = await pool.importFile(file);
118	          if (result.ok) {
119	            const peaks = await pool.getPeaks(result.handle.id, 256);
120	            if (peaks !== undefined) {
121	              setPeaksMap((prev) => {
122	                const next = new Map(prev);
123	                next.set(result.handle.id, peaks);
124	                return next;
125	              });
126	            }
127	          } else {
128	            importErrors.push(result.error);
129	          }
130	        }
131	        if (importErrors.length > 0) {
132	          setErrors(importErrors);
133	        }
134	        setVersion((v) => v + 1);
135	      } finally {
136	        importingRef.current = false;
137	      }
138	    },
139	    [pool],
140	  );
141	
142	  const handleRemove = useCallback(
143	    (id: string) => {
144	      void pool.removeSource(id).then(() => {
145	        setVersion((v) => v + 1);
146	        setPeaksMap((prev) => {
147	          const next = new Map(prev);
148	          next.delete(id);
149	          return next;
150	        });
151	      });
152	    },
153	    [pool],
154	  );
155	
156	  const onFileDrop = useCallback(
157	    (files: File[]) => {
158	      void handleImport(files);
159	    },
160	    [handleImport],
161	  );
162	
163	  const { isDragging, handlers } = useFileDrop(onFileDrop);
164	
165	  const onImportClick = useCallback(() => {
166	    fileInputRef.current?.click();
167	  }, []);
168	
169	  const onFileChange = useCallback(
170	    (e: React.ChangeEvent<HTMLInputElement>) => {
171	      const files = e.target.files;
172	      if (files !== null && files.length > 0) {
173	        void handleImport([...files]);
174	      }
175	    },
176	    [handleImport],
177	  );
178	
179	  return (
180	    <section
181	      data-testid="media-pool-panel"
182	      style={{
183	        ...panelStyle,
184	        ...(isDragging ? { borderColor: "var(--color-blue)" } : {}),
185	      }}
186	      {...handlers}
187	    >
188	      <div style={headerStyle}>
189	        <span>MEDIA POOL</span>
190	        <button type="button" style={importBtnStyle} onClick={onImportClick}>
191	          IMPORT
192	        </button>
193	        <input
194	          ref={fileInputRef}
195	          type="file"
196	          accept="audio/wav,audio/mpeg,audio/ogg,audio/flac,.wav,.mp3,.ogg,.flac"
197	          multiple
198	          style={{ display: "none" }}
199	          onChange={onFileChange}
200	        />
201	      </div>
202	
203	      {errors.length > 0 && (
204	        <div style={errorStyle}>
205	          {errors.map((err, i) => (
206	            <div key={i}>{formatError(err)}</div>
207	          ))}
208	        </div>
209	      )}
210	
211	      {sources.length === 0 ? (
212	        <div style={emptyStyle}>Drop audio files here or click IMPORT</div>
213	      ) : (
214	        <div style={listStyle}>
215	          {sources.map((source) => (
216	            <MediaPoolItem
217	              key={source.id}
218	              source={source}
219	              peaks={peaksMap.get(source.id)}
220	              onRemove={handleRemove}
221	            />
222	          ))}
223	        </div>
224	      )}
225	    </section>
226	  );
227	}
